var DELAYED_BUCKET_DESCRIPTION = "delayed bucket \u2014 \u0440\u0435\u0436\u0438\u043C \u043E\u0442\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0445\u043E\u0434\u0430 \u0432\u043D\u0443\u0442\u0440\u0438 \u0434\u043D\u044F.\n\n\u041A\u0430\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442:\n\u0434\u0435\u043D\u044C \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438 \u043F\u0430\u0440\u0430\u043C\u0435\u0442\u0440\u044B \u0441\u0434\u0435\u043B\u043A\u0438, \u043D\u043E \u0432\u0445\u043E\u0434 \u043D\u0435 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u0440\u0430\u0437\u0443. \u0411\u0430\u043A\u0435\u0442 \u0436\u0434\u0451\u0442, \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u0441\u044F \u043B\u0438 [[delayed-signal|delayed-\u0441\u0438\u0433\u043D\u0430\u043B]] \u2014 \u0434\u043E\u0439\u0434\u0451\u0442 \u043B\u0438 \u0446\u0435\u043D\u0430 \u0434\u043E \u043E\u0442\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F \u0432\u0445\u043E\u0434\u0430.\n\n\u0415\u0441\u043B\u0438 \u0441\u0438\u0433\u043D\u0430\u043B \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u043B\u0441\u044F, \u0441\u0434\u0435\u043B\u043A\u0430 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u043C\u043E\u043C\u0435\u043D\u0442 [[executed-at-utc|ExecutedAtUtc]]. \u0415\u0441\u043B\u0438 \u0446\u0435\u043D\u0430 \u0434\u043E \u0443\u0440\u043E\u0432\u043D\u044F \u043D\u0435 \u0434\u043E\u0448\u043B\u0430, delayed bucket \u0437\u0430 \u044D\u0442\u043E\u0442 \u0434\u0435\u043D\u044C \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0431\u0435\u0437 \u0441\u0434\u0435\u043B\u043A\u0438.\n\n\u041F\u0440\u0438\u043C\u0435\u0440:\n\u043F\u0440\u043E\u0433\u043D\u043E\u0437 \u043D\u0430 \u0434\u0435\u043D\u044C \u0435\u0441\u0442\u044C, \u043D\u043E \u0446\u0435\u043D\u0430 \u0442\u0430\u043A \u0438 \u043D\u0435 \u043A\u043E\u0441\u043D\u0443\u043B\u0430\u0441\u044C delayed-\u0443\u0440\u043E\u0432\u043D\u044F \u2014 \u0432 delayed bucket \u0441\u0434\u0435\u043B\u043A\u0430 \u043D\u0435 \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F.";
var DELAYED_SIGNAL_DESCRIPTION = "delayed-\u0441\u0438\u0433\u043D\u0430\u043B \u2014 \u0443\u0441\u043B\u043E\u0432\u0438\u0435 \u043E\u0442\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0445\u043E\u0434\u0430 \u0432\u043D\u0443\u0442\u0440\u0438 \u0434\u043D\u044F.\n\n\u0427\u0442\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0435\u0442\u0441\u044F:\n\u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0437\u0430\u0440\u0430\u043D\u0435\u0435 \u0440\u0430\u0441\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442 \u0446\u0435\u043D\u0443 \u0432\u0445\u043E\u0434\u0430 \u0438 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0441\u0434\u0435\u043B\u043A\u0443 \u0442\u043E\u043B\u044C\u043A\u043E \u0435\u0441\u043B\u0438 \u0440\u044B\u043D\u043E\u043A \u0432\u043D\u0443\u0442\u0440\u0438 \u043E\u043A\u043D\u0430 \u0440\u0435\u0430\u043B\u044C\u043D\u043E \u0434\u043E\u0445\u043E\u0434\u0438\u0442 \u0434\u043E \u044D\u0442\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u0435\u0441\u043B\u0438 delayed-\u0441\u0438\u0433\u043D\u0430\u043B \u043D\u0435 \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u043B\u0441\u044F, \u044D\u0442\u043E \u043D\u0435 \u043E\u0448\u0438\u0431\u043A\u0430 \u0440\u0430\u0441\u0447\u0451\u0442\u0430, \u0430 \u0448\u0442\u0430\u0442\u043D\u044B\u0439 \u0438\u0441\u0445\u043E\u0434: \u0434\u0435\u043D\u044C \u0438\u043C\u0435\u043B \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435, \u043D\u043E \u0440\u044B\u043D\u043E\u043A \u043D\u0435 \u0434\u0430\u043B \u043D\u0443\u0436\u043D\u0443\u044E \u0446\u0435\u043D\u0443 \u0432\u0445\u043E\u0434\u0430. \u0415\u0441\u043B\u0438 \u0441\u0438\u0433\u043D\u0430\u043B \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u043B\u0441\u044F, \u0441\u0434\u0435\u043B\u043A\u0430 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u043C\u043E\u043C\u0435\u043D\u0442 [[executed-at-utc|ExecutedAtUtc]].";
