var WITH_SL_MODE_DESCRIPTION = "WITH SL \u2014 \u0440\u0435\u0436\u0438\u043C \u0441\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438, \u0433\u0434\u0435 \u0437\u0430\u0449\u0438\u0442\u043D\u044B\u0439 [[tp-sl|stop-loss]] \u0432\u043A\u043B\u044E\u0447\u0451\u043D.\n\n\u0427\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432 \u0441\u0434\u0435\u043B\u043A\u0435:\n\u043F\u043E\u0437\u0438\u0446\u0438\u044F \u043C\u043E\u0436\u0435\u0442 \u0437\u0430\u043A\u0440\u044B\u0442\u044C\u0441\u044F \u0440\u0430\u043D\u044C\u0448\u0435 \u043A\u043E\u043D\u0446\u0430 \u043E\u043A\u043D\u0430 \u043F\u043E [[tp-sl|stop-loss]], [[tp-sl|take-profit]] \u0438\u043B\u0438 [[liquidation|\u043B\u0438\u043A\u0432\u0438\u0434\u0430\u0446\u0438\u0438]]. \u0415\u0441\u043B\u0438 \u043D\u0438 \u043E\u0434\u043D\u043E \u0438\u0437 \u044D\u0442\u0438\u0445 \u0441\u043E\u0431\u044B\u0442\u0438\u0439 \u043D\u0435 \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u043E, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043E\u043A\u043D\u0430 \u0441\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 [[eod|EndOfDay]].\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\nWITH SL \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u044B\u0439 \u0440\u0438\u0441\u043A \u043D\u0430 \u0441\u0434\u0435\u043B\u043A\u0443, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0443\u0431\u044B\u0442\u043E\u043A \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u0443\u044E \u0437\u0430\u0440\u0430\u043D\u0435\u0435 \u0437\u0430\u0434\u0430\u043D\u043D\u0443\u044E \u0433\u0440\u0430\u043D\u0438\u0446\u0443 \u0438 \u043D\u0435 \u043E\u0431\u044F\u0437\u0430\u043D \u0442\u044F\u043D\u0443\u0442\u044C\u0441\u044F \u0434\u043E \u043B\u0438\u043A\u0432\u0438\u0434\u0430\u0446\u0438\u0438.";
var NO_SL_MODE_DESCRIPTION = "NO SL \u2014 \u0440\u0435\u0436\u0438\u043C \u0441\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438 \u0441 \u043E\u0442\u043A\u043B\u044E\u0447\u0451\u043D\u043D\u044B\u043C \u0437\u0430\u0449\u0438\u0442\u043D\u044B\u043C [[tp-sl|stop-loss]].\n\n\u0427\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432 \u0441\u0434\u0435\u043B\u043A\u0435:\n\u043F\u043E\u0437\u0438\u0446\u0438\u044F \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u0434\u043E [[tp-sl|take-profit]], [[liquidation|\u043B\u0438\u043A\u0432\u0438\u0434\u0430\u0446\u0438\u0438]] \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0443\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E [[eod|EndOfDay]]. \u041E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 \u0436\u0451\u0441\u0442\u043A\u043E\u0439 \u0433\u0440\u0430\u043D\u0438\u0446\u044B \u0443\u0431\u044B\u0442\u043A\u0430 \u043F\u043E stop-loss \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u0434\u043D\u044F \u043D\u0435\u0442.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u0440\u0438\u0441\u043A \u0442\u0430\u043A\u043E\u0433\u043E \u0440\u0435\u0436\u0438\u043C\u0430 \u0432\u044B\u0448\u0435. \u0414\u043B\u044F [[isolated-margin|isolated]]-\u043C\u0430\u0440\u0436\u0438 \u044D\u0442\u043E \u043F\u043E\u0432\u044B\u0448\u0430\u0435\u0442 \u0448\u0430\u043D\u0441 \u043F\u043E\u0442\u0435\u0440\u044F\u0442\u044C \u0432\u0435\u0441\u044C \u0437\u0430\u043B\u043E\u0433 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u0441\u0434\u0435\u043B\u043A\u0438, \u0430 \u0434\u043B\u044F [[cross-margin|cross]]-\u043C\u0430\u0440\u0436\u0438 \u2014 \u0432\u0435\u0441\u044C \u0431\u0430\u043B\u0430\u043D\u0441 \u0431\u0430\u043A\u0435\u0442\u0430.";
var FUNDING_DESCRIPTION = "Funding \u2014 \u043F\u0435\u0440\u0438\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u043B\u0430\u0442\u0451\u0436 \u043C\u0435\u0436\u0434\u0443 LONG \u0438 SHORT \u0432 \u0431\u0435\u0441\u0441\u0440\u043E\u0447\u043D\u044B\u0445 \u0444\u044C\u044E\u0447\u0435\u0440\u0441\u0430\u0445.\n\n\u0427\u0442\u043E \u0432\u0430\u0436\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043F\u0440\u043E\u0435\u043A\u0442\u0435:\n\u0432 \u0442\u0435\u043A\u0443\u0449\u0435\u043C \u043E\u0442\u0447\u0451\u0442\u0435 funding \u043D\u0435 \u0432\u043A\u043B\u044E\u0447\u0451\u043D \u0432 \u0440\u0430\u0441\u0447\u0451\u0442 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 PnL \u043E\u0442\u0440\u0430\u0436\u0430\u0435\u0442 \u0446\u0435\u043D\u0443 \u0432\u0445\u043E\u0434\u0430, \u0432\u044B\u0445\u043E\u0434\u0430 \u0438 \u043A\u043E\u043C\u0438\u0441\u0441\u0438\u0438, \u043D\u043E \u043D\u0435 \u044D\u0442\u043E\u0442 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0439 \u0431\u0438\u0440\u0436\u0435\u0432\u043E\u0439 \u043F\u043B\u0430\u0442\u0451\u0436.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u0435\u0441\u043B\u0438 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044F \u043D\u0430 \u0431\u0443\u043C\u0430\u0433\u0435 \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0439 \u0442\u043E\u043B\u044C\u043A\u043E \u0437\u0430 \u0441\u0447\u0451\u0442 \u043E\u0447\u0435\u043D\u044C \u0434\u043E\u043B\u0433\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u043F\u043E\u0437\u0438\u0446\u0438\u0438, \u043D\u0443\u0436\u043D\u043E \u043F\u043E\u043C\u043D\u0438\u0442\u044C, \u0447\u0442\u043E funding \u0437\u0434\u0435\u0441\u044C \u043D\u0435 \u0443\u0447\u0442\u0451\u043D \u0438 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 \u0442\u043E\u0440\u0433\u043E\u0432\u043B\u0435 \u043C\u043E\u0433 \u0431\u044B \u0438\u0437\u043C\u0435\u043D\u0438\u0442\u044C \u0438\u0442\u043E\u0433.";
var SLIPPAGE_DESCRIPTION = "\u041F\u0440\u043E\u0441\u043A\u0430\u043B\u044C\u0437\u044B\u0432\u0430\u043D\u0438\u0435 (slippage) \u2014 \u0440\u0430\u0437\u043D\u0438\u0446\u0430 \u043C\u0435\u0436\u0434\u0443 \u043E\u0436\u0438\u0434\u0430\u0435\u043C\u043E\u0439 \u0438 \u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0446\u0435\u043D\u043E\u0439 \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0441\u0434\u0435\u043B\u043A\u0438.\n\n\u0427\u0442\u043E \u0432\u0430\u0436\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043F\u0440\u043E\u0435\u043A\u0442\u0435:\n\u043F\u0440\u043E\u0441\u043A\u0430\u043B\u044C\u0437\u044B\u0432\u0430\u043D\u0438\u0435 \u0438 price impact \u0432 \u0442\u0435\u043A\u0443\u0449\u0435\u043C \u043E\u0442\u0447\u0451\u0442\u0435 \u043D\u0435 \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u0443\u044E\u0442\u0441\u044F. \u0418\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u043F\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C \u0442\u0435\u0441\u0442\u043E\u0432\u043E\u0433\u043E \u0434\u0432\u0438\u0436\u043A\u0430 \u0431\u0435\u0437 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0443\u0445\u0443\u0434\u0448\u0435\u043D\u0438\u044F \u0446\u0435\u043D\u044B \u0438\u0437-\u0437\u0430 \u043B\u0438\u043A\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u0438 \u0441\u0442\u0430\u043A\u0430\u043D\u0430.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0441\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438 \u043B\u0443\u0447\u0448\u0435 \u0442\u0440\u0430\u043A\u0442\u043E\u0432\u0430\u0442\u044C \u043A\u0430\u043A \u043E\u0446\u0435\u043D\u043A\u0443 \u043B\u043E\u0433\u0438\u043A\u0438 \u0432\u0445\u043E\u0434\u0430 \u0438 \u0440\u0438\u0441\u043A\u0430, \u0430 \u043D\u0435 \u043A\u0430\u043A \u0442\u043E\u0447\u043D\u0443\u044E \u043A\u043E\u043F\u0438\u044E \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0431\u0438\u0440\u0436\u0435\u0432\u043E\u0433\u043E \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0432 \u043C\u043E\u043C\u0435\u043D\u0442\u0435.";
var EOD_DESCRIPTION = "EndOfDay (EOD) \u2014 \u0437\u0430\u043A\u0440\u044B\u0442\u0438\u0435 \u043F\u043E\u0437\u0438\u0446\u0438\u0438 \u043F\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0442\u043E\u0440\u0433\u043E\u0432\u043E\u0433\u043E \u043E\u043A\u043D\u0430.\n\n\u0427\u0442\u043E \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442:\n\u0435\u0441\u043B\u0438 \u0434\u043E \u043A\u043E\u043D\u0446\u0430 \u043E\u043A\u043D\u0430 \u043D\u0435 \u0441\u0440\u0430\u0431\u043E\u0442\u0430\u043B\u0438 [[tp-sl|take-profit]], [[tp-sl|stop-loss]] \u0438\u043B\u0438 [[liquidation|\u043B\u0438\u043A\u0432\u0438\u0434\u0430\u0446\u0438\u044F]], \u043F\u043E\u0437\u0438\u0446\u0438\u044F \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u043D\u0443\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0443 \u0432\u0440\u0435\u043C\u0435\u043D\u0438.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\nEOD \u0432\u0430\u0436\u0435\u043D \u043A\u0430\u043A \u043D\u0435\u0439\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u0432\u044B\u0445\u043E\u0434 \u201C\u043F\u043E \u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u044E \u0434\u043D\u044F\u201D. \u041E\u043D \u043D\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043D\u0438 \u0443\u0441\u043F\u0435\u0445, \u043D\u0438 \u043F\u0440\u043E\u0432\u0430\u043B \u0441\u0430\u043C \u043F\u043E \u0441\u0435\u0431\u0435, \u0430 \u043B\u0438\u0448\u044C \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u0441\u0434\u0435\u043B\u043A\u0430 \u0434\u043E\u0436\u0438\u043B\u0430 \u0434\u043E \u043A\u043E\u043D\u0446\u0430 \u043E\u043A\u043D\u0430 \u0431\u0435\u0437 \u0434\u043E\u0441\u0440\u043E\u0447\u043D\u043E\u0433\u043E \u0441\u043E\u0431\u044B\u0442\u0438\u044F.";
var COUNTERFACT_DESCRIPTION = "\u041A\u043E\u043D\u0442\u0440\u0444\u0430\u043A\u0442 \u2014 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0439 \u0444\u043E\u0440\u043C\u0430\u0442\u0430 \xAB\u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0431\u044B, \u0435\u0441\u043B\u0438 \u0438\u0437\u043C\u0435\u043D\u0438\u0442\u044C \u043E\u0434\u043D\u043E \u0443\u0441\u043B\u043E\u0432\u0438\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\xBB.\n\n\u0427\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0442\u0430\u043A\u043E\u0439 \u0440\u0435\u0436\u0438\u043C:\n\u043E\u043D \u043D\u0435 \u043F\u0435\u0440\u0435\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442 \u0432\u0435\u0441\u044C \u0440\u044B\u043D\u043E\u043A \u0437\u0430\u043D\u043E\u0432\u043E, \u0430 \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0439 \u0444\u0430\u043A\u0442\u043E\u0440 \u0440\u0438\u0441\u043A\u0430 \u0438 \u043F\u043E\u0441\u043C\u043E\u0442\u0440\u0435\u0442\u044C, \u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0441\u0438\u043B\u044C\u043D\u043E \u0438\u043C\u0435\u043D\u043D\u043E \u043E\u043D \u0438\u0441\u043F\u043E\u0440\u0442\u0438\u043B \u0438\u0442\u043E\u0433.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u043A\u043E\u043D\u0442\u0440\u0444\u0430\u043A\u0442 \u043F\u043E\u043B\u0435\u0437\u0435\u043D \u0434\u043B\u044F \u0434\u0438\u0430\u0433\u043D\u043E\u0441\u0442\u0438\u043A\u0438 \u0445\u0432\u043E\u0441\u0442\u0430 \u0440\u0438\u0441\u043A\u0430, \u043D\u043E \u043D\u0435 \u0437\u0430\u043C\u0435\u043D\u044F\u0435\u0442 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0439 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0441\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438 \u0438 \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u0434\u043C\u0435\u043D\u044F\u0442\u044C \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C \u0434\u043E\u0445\u043E\u0434\u043D\u043E\u0441\u0442\u0438.";
var FIRST_EVENT_DESCRIPTION = "First-event \u2014 \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u0432\u044B\u0431\u043E\u0440\u0430 \u0432\u044B\u0445\u043E\u0434\u0430 \u0432 1m-\u0441\u0432\u0435\u0447\u0435, \u043A\u043E\u0433\u0434\u0430 \u0446\u0435\u043D\u0430 \u0432\u043D\u0443\u0442\u0440\u0438 \u043E\u0434\u043D\u043E\u0439 \u043C\u0438\u043D\u0443\u0442\u044B \u0437\u0430\u0434\u0435\u043B\u0430 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0443\u0440\u043E\u0432\u043D\u0435\u0439 \u0441\u0440\u0430\u0437\u0443.\n\n\u041F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442 \u043A\u043E\u043D\u0441\u0435\u0440\u0432\u0430\u0442\u0438\u0432\u043D\u044B\u0439 (\u043D\u0430\u0438\u0445\u0443\u0434\u0448\u0438\u0439 \u0434\u043B\u044F \u043F\u043E\u0437\u0438\u0446\u0438\u0438):\nliquidation -> stop-loss -> take-profit.\n\n\u0415\u0441\u043B\u0438 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u043E\u0432 \u0432 \u043C\u0438\u043D\u0443\u0442\u0435 \u043D\u0435\u0442, \u0441\u0434\u0435\u043B\u043A\u0430 \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E \u043E\u0431\u044B\u0447\u043D\u043E\u043C\u0443 \u043F\u0435\u0440\u0432\u043E\u043C\u0443 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E\u043C\u0443 \u0443\u0440\u043E\u0432\u043D\u044E.\n\n\u0415\u0441\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0438 \u0434\u043D\u044F \u043D\u0438 \u043E\u0434\u0438\u043D \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u043D\u0435 \u0441\u0440\u0430\u0431\u043E\u0442\u0430\u043B, \u043F\u043E\u0437\u0438\u0446\u0438\u044F \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E [[eod|EndOfDay]].\n\n\u042D\u0442\u043E \u0440\u0435\u0434\u043A\u0438\u0439 \u043A\u0435\u0439\u0441: \u0434\u043B\u044F \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u0430 \u043D\u0443\u0436\u043D\u043E, \u0447\u0442\u043E\u0431\u044B \u0432 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u0445 \u043E\u0434\u043D\u043E\u0439 \u043C\u0438\u043D\u0443\u0442\u044B \u0446\u0435\u043D\u0430 \u0443\u0441\u043F\u0435\u043B\u0430 \u0437\u0430\u0434\u0435\u0442\u044C, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0438 stop-loss, \u0438 take-profit.\n\n[[why-first-event|\u041F\u043E\u0447\u0435\u043C\u0443?]]";
var WHY_FIRST_EVENT_DESCRIPTION = "\u041F\u043E\u0447\u0435\u043C\u0443 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0445\u0443\u0434\u0448\u0438\u0439 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0439:\n\u0432 \u043E\u0434\u043D\u043E\u0439 \u043C\u0438\u043D\u0443\u0442\u043D\u043E\u0439 \u0441\u0432\u0435\u0447\u0435 \u043D\u0435\u0442 \u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u043D\u043E\u0433\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0430 \u043A\u0430\u0441\u0430\u043D\u0438\u0439 \u0432\u043D\u0443\u0442\u0440\u0438 \u043C\u0438\u043D\u0443\u0442\u044B, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \xAB\u043B\u0443\u0447\u0448\u0438\u0439\xBB \u0438\u0441\u0445\u043E\u0434 \u043D\u0435\u043B\u044C\u0437\u044F \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u043F\u043E \u0438\u0441\u0442\u043E\u0440\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0434\u0430\u043D\u043D\u044B\u043C \u0441\u0432\u0435\u0447\u0438.\n\n\u0415\u0441\u043B\u0438 \u0432\u044B\u0431\u0440\u0430\u0442\u044C \u043B\u0443\u0447\u0448\u0438\u0439 \u0438\u0441\u0445\u043E\u0434, \u043E\u0442\u0447\u0451\u0442 \u0441\u0442\u0430\u043D\u0435\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E \u043E\u043F\u0442\u0438\u043C\u0438\u0441\u0442\u0438\u0447\u043D\u044B\u043C \u0438 \u0437\u0430\u043D\u0438\u0437\u0438\u0442 \u0440\u0438\u0441\u043A.\n\n\u041F\u043E\u044D\u0442\u043E\u043C\u0443 first-event \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0435\u0442 \u043A\u043E\u043D\u0441\u0435\u0440\u0432\u0430\u0442\u0438\u0432\u043D\u044B\u0439 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u043F\u043E \u0445\u0443\u0434\u0448\u0435\u043C\u0443 \u0438\u0441\u0445\u043E\u0434\u0443, \u0447\u0442\u043E\u0431\u044B \u0431\u0438\u0437\u043D\u0435\u0441-\u043E\u0446\u0435\u043D\u043A\u0430 \u043D\u0435 \u0431\u044B\u043B\u0430 \u043F\u0440\u0438\u0443\u043A\u0440\u0430\u0448\u0435\u043D\u0430.";
var WHY_BUCKET_DESCRIPTION = "\u041F\u043E\u0447\u0435\u043C\u0443 \u0431\u0430\u043A\u0435\u0442\u044B \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u044B:\n\u043A\u0430\u0436\u0434\u044B\u0439 \u0431\u0430\u043A\u0435\u0442 \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u0443\u0435\u0442 \u0440\u0430\u0437\u043D\u0443\u044E \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0443 \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F (\u043E\u0434\u0438\u043D \u0432\u0445\u043E\u0434 \u0432 \u0434\u0435\u043D\u044C, \u043F\u0435\u0440\u0435\u0437\u0430\u0445\u043E\u0434\u044B \u0432\u043D\u0443\u0442\u0440\u0438 \u0434\u043D\u044F, \u043E\u0442\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0439 \u0432\u0445\u043E\u0434).\n\n\u0415\u0441\u043B\u0438 \u0441\u043C\u0435\u0448\u0430\u0442\u044C \u0438\u0445 \u0432 \u043E\u0434\u0438\u043D \u043A\u0430\u043F\u0438\u0442\u0430\u043B \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0441\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438, \u043F\u043E\u0442\u0435\u0440\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 \u0438 \u0441\u0442\u0430\u043D\u0435\u0442 \u043D\u0435\u043F\u043E\u043D\u044F\u0442\u043D\u043E, \u043A\u0430\u043A\u043E\u0439 \u0438\u043C\u0435\u043D\u043D\u043E \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C \u0434\u0430\u043B \u0440\u0438\u0441\u043A \u0438\u043B\u0438 \u0434\u043E\u0445\u043E\u0434\u043D\u043E\u0441\u0442\u044C.\n\n\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043A\u0430\u043F\u0438\u0442\u0430\u043B \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u0441\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F \u0440\u0430\u0437\u0434\u0435\u043B\u044C\u043D\u043E, \u0430 aggregate \u0441\u0442\u0440\u043E\u0438\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u0430\u043A \u0441\u0443\u043C\u043C\u0430 \u0443\u0436\u0435 \u0433\u043E\u0442\u043E\u0432\u044B\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432.";
var TOTAL_PNL_DESCRIPTION = "TotalPnl% \u2014 \u0438\u0442\u043E\u0433\u043E\u0432\u0430\u044F \u0434\u043E\u0445\u043E\u0434\u043D\u043E\u0441\u0442\u044C \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u043D\u0442\u0430\u0445 \u0432 \u0432\u044B\u0431\u0440\u0430\u043D\u043D\u043E\u043C \u0441\u0440\u0435\u0437\u0435 \u043E\u0442\u0447\u0451\u0442\u0430.\n\n\u0427\u0442\u043E \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043C\u0435\u0442\u0440\u0438\u043A\u0430:\n\u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u044B\u0440\u043E\u0441 \u0438\u043B\u0438 \u0443\u043F\u0430\u043B \u043A\u0430\u043F\u0438\u0442\u0430\u043B \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0442\u0430\u0440\u0442\u043E\u0432\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F \u043F\u043E\u0441\u043B\u0435 \u0443\u0436\u0435 \u0437\u0430\u043A\u0440\u044B\u0442\u044B\u0445 \u0441\u0434\u0435\u043B\u043E\u043A \u044D\u0442\u043E\u0433\u043E \u0441\u0440\u0435\u0437\u0430.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u0432\u044B\u0441\u043E\u043A\u0438\u0439 TotalPnl% \u0441\u0430\u043C \u043F\u043E \u0441\u0435\u0431\u0435 \u0435\u0449\u0451 \u043D\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0445\u043E\u0440\u043E\u0448\u0443\u044E \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044E. \u0415\u0433\u043E \u043D\u0443\u0436\u043D\u043E \u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0442\u044C \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 [[drawdown|MaxDD%]], [[liquidation|HadLiq]] \u0438 [[account-ruin|AccRuin]], \u0447\u0442\u043E\u0431\u044B \u0434\u043E\u0445\u043E\u0434\u043D\u043E\u0441\u0442\u044C \u043D\u0435 \u0431\u044B\u043B\u0430 \u043A\u0443\u043F\u043B\u0435\u043D\u0430 \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u044B\u043C \u0440\u0438\u0441\u043A\u043E\u043C.";
var WEALTH_PCT_DESCRIPTION = "Wealth% \u2014 \u0434\u043E\u0445\u043E\u0434\u043D\u043E\u0441\u0442\u044C \u0441 \u0443\u0447\u0451\u0442\u043E\u043C \u0443\u0436\u0435 \u0432\u044B\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0431\u044B\u043B\u0438, \u0430 \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0435\u043A\u0443\u0449\u0435\u0433\u043E \u0431\u0430\u043B\u0430\u043D\u0441\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0449\u0451 \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0432 \u0440\u044B\u043D\u043A\u0435.\n\n\u0427\u0442\u043E \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043F\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044E \u0441 TotalPnl%:\n\u0432 Wealth% \u0443\u0447\u0438\u0442\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0434\u0435\u043D\u044C\u0433\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044F \u0443\u0436\u0435 \u0441\u043D\u044F\u043B\u0430 \u0441 \u0440\u0430\u0431\u043E\u0447\u0435\u0433\u043E \u0431\u0430\u043B\u0430\u043D\u0441\u0430 \u0438 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0434\u0435\u0440\u0436\u0438\u0442 \u0432\u043D\u0443\u0442\u0440\u0438 \u0441\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u0435\u0441\u043B\u0438 Wealth% \u0432\u044B\u0448\u0435, \u0447\u0435\u043C [[total-pnl|TotalPnl%]], \u0447\u0430\u0441\u0442\u044C \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 \u0443\u0436\u0435 \u0437\u0430\u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u0430 \u0432\u044B\u0432\u043E\u0434\u0430\u043C\u0438 \u0438 \u043D\u0435 \u0432\u0438\u0434\u043D\u0430 \u0432 \u043E\u0434\u043D\u043E\u043C \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0435\u043A\u0443\u0449\u0435\u043C equity.";
var NET_PNL_USD_DESCRIPTION = "NetPnl$ \u2014 \u0447\u0438\u0441\u0442\u044B\u0439 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u043E\u0434\u043D\u043E\u0439 \u0441\u0434\u0435\u043B\u043A\u0438 \u0432 \u0434\u043E\u043B\u043B\u0430\u0440\u0430\u0445 \u043F\u043E\u0441\u043B\u0435 \u043A\u043E\u043C\u0438\u0441\u0441\u0438\u0439.\n\n\u0427\u0442\u043E \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043F\u043E\u043B\u0435:\n\u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043F\u0440\u0438\u0431\u044B\u043B\u044C \u043F\u043E \u0441\u0434\u0435\u043B\u043A\u0435, \u043E\u0442\u0440\u0438\u0446\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u2014 \u0443\u0431\u044B\u0442\u043E\u043A \u0443\u0436\u0435 \u043F\u043E\u0441\u043B\u0435 \u0432\u044B\u0447\u0435\u0442\u0430 \u0442\u043E\u0440\u0433\u043E\u0432\u044B\u0445 \u043A\u043E\u043C\u0438\u0441\u0441\u0438\u0439.\n\n\u041A\u0430\u043A \u0447\u0438\u0442\u0430\u0442\u044C:\n\u044D\u0442\u043E \u0434\u0435\u043D\u0435\u0436\u043D\u0430\u044F \u043C\u0435\u0442\u0440\u0438\u043A\u0430 \u043E\u0434\u043D\u043E\u0439 \u043F\u043E\u0437\u0438\u0446\u0438\u0438, \u0430 \u043D\u0435 \u0432\u0441\u0435\u0439 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438. \u0412 \u0440\u0435\u0436\u0438\u043C\u0435 NO BIGGEST LIQ LOSS \u0438\u043C\u0435\u043D\u043D\u043E \u043F\u043E NetPnl$ \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u0430\u044F \u0443\u0431\u044B\u0442\u043E\u0447\u043D\u0430\u044F [[liquidation|\u043B\u0438\u043A\u0432\u0438\u0434\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F]] \u0441\u0434\u0435\u043B\u043A\u0430 \u0434\u043B\u044F \u043A\u043E\u043D\u0442\u0440\u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0441\u0447\u0451\u0442\u0430.";
